//215. Kth Largest Element in an Array https://leetcode.com/problems/kth-largest-element-in-an-array/
public  Queue fixedQueue(Collection ts, int k, Comparator comparator) {
  Queue queue = new PriorityQueue<>(k, comparator);
  for (T t : ts) {
    // 此处有判断size再插入的方法，但是性能差距不大
    queue.add(t);
    if (queue.size() > k) {
      queue.poll();
    }
  }
  return queue;
}

